select

from order_info oi
left join customer c on oi.customer_id = c.id
left join service_item si on oi.service_item_id = si.id

    oi.deleted = 0

        and oi.order_no like concat('%', #{query.orderNo}, '%')


        and c.name like concat('%', #{query.customerName}, '%')


        and oi.payment_method = #{query.paymentMethod}


        and oi.pay_status = #{query.payStatus}


        and oi.debt_status = #{query.debtStatus}


        and oi.order_status = #{query.orderStatus}


        and oi.create_time >= #{query.beginTime}


        and oi.create_time <= #{query.endTime}


order by oi.create_time desc

